<template>
    <div id="nav-container">
        <nav class="navbar navbar-expand-lg navbar-dark bg-dark">
            <a class="navbar-brand" href="javascript:void(0)">
                <!--<img src="https://oj.ctguacm.work/image/ctgu.png" height="30"> CTGUACM Online Judge-->
            </a>
            <button class="navbar-toggler" type="button" data-toggle="collapse" data-target="#navbarSupportedContent"
                    aria-controls="navbarSupportedContent" aria-expanded="false" aria-label="Toggle navigation">
                <span class="navbar-toggler-icon"></span>
            </button>
            <div class="collapse navbar-collapse" id="navbarSupportedContent">
                <ul class="navbar-nav mr-auto">
                    <li class="nav-item">
                        <a class="nav-link" v-bind:class="{ 'active': isActive == 'index' }" href="/">{{$t('DEFAULT.OJ_HOME_PAGE')}}</a>
                    </li>
                    <li class="nav-item">
                        <a class="nav-link" v-bind:class="{ 'active': isActive == 'problemset' }"
                           href="/problemset.html">{{$t('DEFAULT.OJ_PROBLEMSET_PAGE')}}</a>
                    </li>
                    <li class="nav-item">
                        <a class="nav-link" v-bind:class="{ 'active': isActive == 'status' }" href="/status.html">{{$t('DEFAULT.OJ_STATUS_PAGE')}}</a>
                    </li>
                    <li class="nav-item">
                        <a class="nav-link" v-bind:class="{ 'active': isActive == 'ranklist' }" href="/ranklist.html">{{$t('DEFAULT.OJ_RANKLIST_PAGE')}}</a>
                    </li>
                </ul>
                <ul class="navbar-nav mundb-nav-right">
                    <template v-if="isLogin == false">
                        <li class="nav-item mundb-no-shrink">
                            <a class="nav-link" v-bind:class="{ 'active': isActive == 'account' }"
                               href="loginpage.html">{{$t('DEFAULT.OJ_MESSAGE_LOGIN_OR_REGISTER')}}</a>
                        </li>
                    </template>
                    <template v-else-if="isLogin == true">
                        <li class="nav-item dropdown mundb-btn-ucenter">
                            <a class="nav-link dropdown-toggle" data-toggle="dropdown" href="#" role="button"
                               aria-haspopup="true" aria-expanded="false">
                                {{settings.welcome}},
                                <span id="nav-username">{{user.nick}}</span>
                            </a>
                            <div class="dropdown-menu dropdown-menu-right">
                                <div class="dropdown-header">
                                    <img src="@/assets/images/user/default.png" class="mundb-avatar"
                                         id="atsast_nav_avatar">
                                    <div>
                                        <h6><span id="nav-dropdown-username">{{user.nick}}</span><br>
                                            <small>{{user.email}}</small>
                                        </h6>
                                    </div>
                                </div>
                                <div class="dropdown-divider"></div>
                                <a class="dropdown-item" href="javascript:void(0)">
                                    <i class="material-icons prefix">account_circle</i>
                                    &nbsp;&nbsp;{{$t('DEFAULT.OJ_MESSAGE_INFORMATION')}}
                                </a>
                                <a class="dropdown-item" href="javascript:void(0)">
                                    <i class="material-icons prefix">settings</i>
                                    &nbsp;&nbsp;{{$t('DEFAULT.OJ_MESSAGE_SETTINGS')}}
                                </a>
                                <a class="dropdown-item" href="/admin">
                                    <i class="material-icons prefix">face</i>
                                    &nbsp;&nbsp;{{$t('DEFAULT.OJ_MESSAGE_ADMIN')}}
                                </a>
                                <div class="dropdown-divider"></div>
                                <a class="dropdown-item" href="javascript:void(0)">
                                    <i class="material-icons prefix">group</i>
                                    &nbsp;&nbsp;{{$t('DEFAULT.OJ_MESSAGE_MY_TEAM')}}
                                </a>
                                <a class="dropdown-item" href="javascript:void(0)">
                                    <i class="material-icons prefix">insert_invitation</i>
                                    &nbsp;&nbsp;{{$t('DEFAULT.OJ_MESSAGE_MY_SUBMISSION')}}
                                </a>
                                <div class="dropdown-divider"></div>
                                <a class="dropdown-item text-danger" href="javascript:void(0)">
                                    <i class="material-icons prefix">bug_report</i>
                                    &nbsp;&nbsp;{{$t('DEFAULT.OJ_MESSAGE_MY_REPORT_BUG')}}
                                </a>
                                <a class="dropdown-item text-danger" style="cursor: pointer" @click="logout">
                                    <i class="material-icons prefix">exit_to_app</i>
                                    &nbsp;&nbsp;{{$t('DEFAULT.OJ_MESSAGE_MY_LOGOUT')}}
                                </a>
                            </div>
                        </li>
                    </template>
                    <template v-else>
                        <li class="nav-item mundb-no-shrink"></li>
                    </template>
                </ul>
            </div>
        </nav>
    </div>
</template>
<script>

    import fun from '@/assets/js/OJFunction'
    import '@/assets/js/include.js'

    export default {
        name: 'nav-bar',
        data() {
            return {
                settings: {
                    accessToken: "",
                    refreshToken: "",
                    welcome: ""
                },
            }
        },
        props: ['isActive', 'isLogin', 'user'],
        methods: {
            logout: function () {
                var _this = this
                window.axios.post(_this.GLOBAL.OJ_DEFAULT_BACK_SERVE + '/account/logout', {}, {
                    headers: {
                        OJ_ACCESS_TOKEN: fun.getCookie("AccessToken"),
                    }
                }).then(function (res) {
                    var error = res.data.OJ_ERROR_TYPE;
                    if (error == _this.GLOBAL.OJ_ERROR_NO_ERROR) {
                        fun.delCookie("RefreshToken");
                        fun.delCookie("AccessToken");
                        location.reload();
                    }
                }).catch(function (error) {
                    console.log(error)
                })
            }
        },
        created() {
            let myDate = new Date();
            var h = myDate.getHours();
            var m = myDate.getMinutes();
            if (h >= 22 || h <= 6) this.settings.welcome = "Are you a night owl！";
            else if (h == 7 || h == 8) this.settings.welcome = "Breakfast time！";
            else if ((h >= 9 && h <= 10) || (h == 11 && m <= 30)) this.settings.welcome = "Happy forenoon~~！";
            else if ((h == 11 && m > 30) || (h >= 12 && h <= 13)) this.settings.welcome = "Have lunch^_^！";
            else if ((h >= 14 && h <= 17)) this.settings.welcome = "Coding...！";
            else if ((h == 18)) this.settings.welcome = "Dinner is love！";
            else this.settings.welcome = "Sweet dream！";
        }


    }
</script>
<style lang="scss" scoped>
    #nav-container {
        .dropdown-item {
            white-space: pre-wrap;
        }
        margin-bottom: 30px;
        position: sticky;
        top: 0;
        z-index: 899;
        flex-shrink: 0;
        flex-grow: 0;
    }
</style>